interpretedFindings.codeExample:
# Nginx — start with report-only to avoid breaking the app
add_header Content-Security-Policy-Report-Only "
  default-src 'self';
  script-src 'self' 'nonce-{RANDOM_NONCE}';
  style-src 'self' 'unsafe-inline';
  img-src 'self' data: https:;
  font-src 'self';
  connect-src 'self';
  frame-ancestors 'none';
  report-uri /csp-report-endpoint
" always;

# Once validated, switch to enforcing:
add_header Content-Security-Policy "default-src 'self'; script-src 'self' 'nonce-{RANDOM_NONCE}'; ..." always;
